userEnteredValue.formulaValue:
={"Pot Up Rows Per Trays";
ARRAY_CONSTRAIN(
ArrayFormula(if(A5:A="","",sumif('Define Crop Terms'!$N:$N,$S5:$S,'Define Crop Terms'!$P:$P)))
,match("zzzz",$A$5:$A,1),1)}

={"Pot Up Cells Per Row";
ARRAY_CONSTRAIN(
ArrayFormula(if(A5:A="","",sumif('Define Crop Terms'!$N:$N,$S5:$S,'Define Crop Terms'!$Q:$Q)))
,match("zzzz",$A$5:$A,1),1)}

={"Seeded Pot Up Rows Per Trays";
ARRAY_CONSTRAIN(
ArrayFormula(if(A5:A="","",sumif('Define Crop Terms'!$N:$N,$V5:$V,'Define Crop Terms'!$P:$P)))
,match("zzzz",$A$5:$A,1),1)}

={"Seeded Pot Up Cells Per Row";
ARRAY_CONSTRAIN(
ArrayFormula(if(A5:A="","",sumif('Define Crop Terms'!$N:$N,$V5:$V,'Define Crop Terms'!$Q:$Q)))
,match("zzzz",$A$5:$A,1),1)}

={"Average Yield";
ARRAY_CONSTRAIN(
map(A5:A,lambda(Crop,if(crop="","",round(iferror(sumproduct('Crop by Season'!A:A=Crop,'Crop by Season'!I:I,'Crop by Season'!J:J)/countif('Crop by Season'!A:A,Crop),0),1))))
,match("zzzz",$A$5:$A,1),1)}

